module SR_latch (  
    input SR_S,  
    input R,  
    output reg Q,  
    output reg Q_bar  
);  
    always @ (SR_S or R) begin  
        if (SR_S && !R) begin  
            Q <= 1;  
            Q_bar <= 0;  
        end else if (!SR_S && R) begin  
            Q <= 0;  
            Q_bar <= 1;  
        end  
        // Retain previous state when both SR_S and R are low  
    end  
endmodule
